const repos = ($env.GITHUB_REPOS || '').split(',').map(r => r.trim()).filter(Boolean);
if (repos.length === 0) return [];
return repos.map(repo => ({ json: { repo } }));

// Draft除外 + レビュアーフィルタ + 重複防止 + tracked管理

const staticData = $getWorkflowStaticData('global');
const reviewed = staticData.reviewed || {};
const tracked = staticData.tracked || {};
const threads = staticData.threads || {};
const newPRs = [];

const targetReviewers = ($env.GITHUB_REVIEWERS || '').split(',').map(r => r.trim()).filter(Boolean);
const targetTeams = ($env.GITHUB_TEAMS || '').split(',').map(t => t.trim()).filter(Boolean);

// #4対策: 今回のポーリングで見えたPRキーを記録
const seenKeys = new Set();
// #12対策: 正常にAPIレスポンスを得たリポジトリを記録
const successRepos = new Set();

for (const item of $input.all()) {
  const prs = Array.isArray(item.json) ? item.json : [item.json];

  // APIエラーの場合はスキップ（prにnumberやheadがないのはエラーレスポンス）
  let repoHasValidPR = false;

  for (const pr of prs) {
    if (!pr.number || !pr.head) continue;
    repoHasValidPR = true;

    const key = pr.base.repo.full_name + '#' + pr.number;
    seenKeys.add(key);
    successRepos.add(pr.base.repo.full_name);

    if (pr.draft) continue;

    const headSha = pr.head.sha;
    const reviewers = (pr.requested_reviewers || []).map(r => r.login);
    const teams = (pr.requested_teams || []).map(t => t.slug);
    const noFilter = targetReviewers.length === 0 && targetTeams.length === 0;
    const matchUser = targetReviewers.some(t => reviewers.includes(t));
    const matchTeam = targetTeams.some(t => teams.includes(t));
    const isAuthor = targetReviewers.includes(pr.user.login);
    const isTracked = tracked[key] === true;

    if (!noFilter && !matchUser && !matchTeam && !isAuthor && !isTracked) continue;
    if (matchUser || matchTeam || isAuthor) tracked[key] = true;
    // reviewed: sha文字列 or {sha,ts}オブジェクト両対応
    const rev = reviewed[key];
    const revSha = (rev && typeof rev === 'object') ? rev.sha : rev;
    // 同じSHAならスキップ（失敗リトライ中で上限未満の場合は通過）
    if (revSha === headSha) {
      if (!(rev && rev.failed && (rev.retryCount || 0) < 3)) continue;
    }

    newPRs.push({ json: {
      number: pr.number, title: pr.title, body: pr.body || '',
      head_ref: pr.head.ref, base_ref: pr.base.ref,
      head_sha: headSha, repo_name: pr.base.repo.name,
      repo_full_name: pr.base.repo.full_name,
      html_url: pr.html_url, user: pr.user.login,
      _key: key
    }});
  }
}

// #4 + #12対策: tracked/reviewed/threads からクローズ済みPRを削除
// ただし、正常にAPIレスポンスを得たリポのPRのみ対象
// APIエラーのリポのPRは消さない（再レビュー暴走を防止）
for (const key of Object.keys(tracked)) {
  const repoName = key.split('#')[0];
  if (successRepos.has(repoName) && !seenKeys.has(key)) {
    delete tracked[key];
    delete reviewed[key];
    delete threads[key];
  }
}

staticData.reviewed = reviewed;
staticData.tracked = tracked;
staticData.threads = threads;
if (newPRs.length === 0) return [];
return newPRs;

// #1対策: base64エンコードでシェルインジェクション防止
const pr = $input.first().json;
const payload = {
  repo_name: pr.repo_name,
  head_ref: pr.head_ref,
  base_ref: pr.base_ref,
  title: pr.title,
  body: pr.body,
  number: String(pr.number),
  _key: pr._key,
  head_sha: pr.head_sha,
  html_url: pr.html_url,
  user: pr.user
};
const encoded = Buffer.from(JSON.stringify(payload)).toString('base64');
return [{ json: { ...pr, encoded } }];

// Claude Code でレビュー実行（非同期 - ワーカーブロック回避）
const { exec } = require('child_process');
const encoded = $input.first().json.encoded;

return new Promise((resolve) => {
  const child = exec(
    `docker exec claude-review-runner bash /scripts/review.sh "${encoded}"`,
    { timeout: 960000, maxBuffer: 10 * 1024 * 1024, encoding: 'utf-8' },
    (error, stdout, stderr) => {
      if (error) {
        resolve([{ json: { stdout: stdout || error.message, exitCode: error.code || 1 } }]);
      } else {
        resolve([{ json: { stdout: stdout, exitCode: 0 } }]);
      }
    }
  );
});

// レビュー成功時のみ reviewed にマーク + 既存スレッド検索
const staticData = $getWorkflowStaticData('global');
const reviewed = staticData.reviewed || {};
const threads = staticData.threads || {};

const rawStdout = ($input.first().json.stdout || '').trim();
const exitCode = $input.first().json.exitCode;
const pr = $('Filter').item.json;
const slackChannel = $env.SLACK_CHANNEL || '#code-review';

let review;
let parseSuccess = false;
let debugInfo = '';

// stdoutからJSON部分を抽出（git出力等のプレフィックスを除去）
function extractJson(text) {
  try { return JSON.parse(text); } catch(_) {}
  const first = text.indexOf('{');
  const last = text.lastIndexOf('}');
  if (first >= 0 && last > first) {
    try { return JSON.parse(text.substring(first, last + 1)); } catch(_) {}
  }
  return null;
}

try {
  const parsed = extractJson(rawStdout);
  if (!parsed) {
    debugInfo = 'JSON extraction failed | stdout first 300 chars: ' + rawStdout.substring(0, 300);
    throw new Error(debugInfo);
  }

  // review.sh がエラーを返した場合
  if (parsed.failed) {
    if (parsed.concurrent) return [];
    const isReReview = !!reviewed[pr._key];
    const prevRetry = (reviewed[pr._key] && reviewed[pr._key].failed && reviewed[pr._key].sha === pr.head_sha) ? (reviewed[pr._key].retryCount || 0) : 0;
    const retryCount = prevRetry + 1;
    reviewed[pr._key] = { sha: pr.head_sha, ts: Date.now(), failed: true, retryCount };
    staticData.reviewed = reviewed;
    const retryLabel = retryCount >= 3 ? '（最終リトライ — 以降スキップ）' : '（リトライ ' + retryCount + '/3）';
    return [{ json: {
      skip: false, isError: true, isReReview,
      parentText: '❌ PR #' + pr.number + ' ' + pr.title + '  レビュー失敗 ' + retryLabel,
      linkMsg: '🔗 ' + pr.html_url + '\nエラー: ' + (parsed.error || '不明なエラー'),
      issueMessages: [], goodMsg: '', manualMsg: '',
      switchCmd: '💻 *手動確認コマンド*\n```cd ~/Develop/' + pr.repo_name + ' && git checkout ' + pr.head_ref + ' && claude```',
      pr: pr, slackChannel: slackChannel
    }}];
  }

  // Case 1: review.sh が直接レビューJSONを返した場合（summary があるか）
  if (parsed.summary !== undefined) {
    review = parsed;
    parseSuccess = true;
  }
  // Case 2: Claude ラッパー JSON（{"type":"result","result":"..."}）の場合
  else if (parsed.result) {
    let resultText = parsed.result;
    // ```json ... ``` ブロックを除去
    resultText = resultText.replace(/```json\s*/g, '').replace(/```\s*/g, '');
    const inner = extractJson(resultText);
    if (inner && (inner.summary !== undefined || inner.issues !== undefined)) {
      review = inner;
      parseSuccess = true;
    }
  }

  if (!parseSuccess) {
    const text = parsed.result || parsed.summary || rawStdout;
    review = { summary: text, score: '?', issues: [] };
    if (text && text.length > 10) parseSuccess = true;
  }
} catch (e) {
  review = { summary: 'レビュー結果のパースに失敗しました。' + (debugInfo || e.message), score: '?', issues: [] };
  parseSuccess = false;
}

// 再レビュー判定（reviewed にセットする前に判定）
const isReReview = !!reviewed[pr._key];

// パース成功時のみ reviewed にマーク
let retryCount = 0;
if (parseSuccess) {
  reviewed[pr._key] = { sha: pr.head_sha, ts: Date.now() };
} else {
  const prev = reviewed[pr._key];
  const prevRetry = (prev && prev.failed && prev.sha === pr.head_sha) ? (prev.retryCount || 0) : 0;
  retryCount = prevRetry + 1;
  reviewed[pr._key] = { sha: pr.head_sha, ts: Date.now(), failed: true, retryCount };
}
staticData.reviewed = reviewed;

const critical = (review.issues || []).filter(i => i.severity === 'Critical');
const warning = (review.issues || []).filter(i => i.severity === 'Warning');
const info = (review.issues || []).filter(i => i.severity === 'Info');

const counts = [];
if (critical.length) counts.push('🔴' + critical.length);
if (warning.length) counts.push('🟡' + warning.length);
if (info.length) counts.push('🔵' + info.length);
const countStr = counts.length > 0 ? counts.join(' ') : '✅ 問題なし';

const retryLabel = retryCount > 0 ? (retryCount >= 3 ? ' （最終リトライ — 以降スキップ）' : ' （リトライ ' + retryCount + '/3）') : '';
const parentText = '🔍 PR #' + pr.number + ' ' + pr.title + '\n📊 Score: ' + (review.score || '?') + '  ' + countStr + retryLabel;
const linkMsg = '🔗 ' + pr.html_url + '\n👤 ' + pr.user + '  `' + pr.head_ref + '` → `' + pr.base_ref + '`\n\n📝 *サマリー*\n' + (review.summary || '');

const issueMessages = (review.issues || []).map(issue => {
  const icon = issue.severity === 'Critical' ? '🔴' : issue.severity === 'Warning' ? '🟡' : '🔵';
  return icon + ' *' + issue.severity + ' — ' + issue.category + '*\n📄 `' + issue.file + ':' + issue.line + '`\n' + issue.description + '\n💡 `' + issue.suggestion + '`';
});

let goodMsg = '';
if (review.good_points && review.good_points.length > 0) {
  goodMsg = '✅ *良い点*\n' + review.good_points.map(p => '• ' + p).join('\n');
}

let manualMsg = '';
if (review.needs_manual_review) {
  manualMsg = '⚠️ *手動レビュー推奨*\n' + (review.manual_review_reason || '');
}

const switchCmd = '💻 *手動確認コマンド*\n```cd ~/Develop/' + pr.repo_name + ' && git checkout ' + pr.head_ref + ' && claude```';

return [{ json: { skip: false, isError: false, isReReview, parentText, linkMsg, issueMessages, goodMsg, manualMsg, switchCmd, pr, slackChannel } }];

// staticDataからスレッド情報を取得し、データを準備
const staticData = $getWorkflowStaticData('global');
const threads = staticData.threads || {};
const data = $input.first().json;
const threadTs = threads[data.pr._key];
const hasThread = !!(threadTs && typeof threadTs === 'string' && threadTs.includes('.'));

// 新規親メッセージ作成時のメンション・ラベル付与
let parentText = data.parentText;
if (!hasThread) {
  const mentionIds = ($env.SLACK_MENTION || '').split(',').map(s => s.trim()).filter(Boolean);
  const mention = mentionIds.length > 0 ? mentionIds.map(id => '<@' + id + '>').join(' ') : '';
  if (data.isReReview) {
    parentText = '🔄 *再レビュー* ' + mention + '\n' + data.parentText;
  } else if (mention) {
    parentText = data.parentText + '\n' + mention;
  }
}

return [{ json: { ...data, hasThread, threadTs: threadTs || '', parentText } }];

// 既存スレッドへの再レビュー追記（メンション付き）
const data = $input.first().json;
const parentTs = data.threadTs;
const messages = [];

const mentionIds = ($env.SLACK_MENTION || '').split(',').map(s => s.trim()).filter(Boolean);
const mention = mentionIds.length > 0 ? mentionIds.map(id => '<@' + id + '>').join(' ') : '';
const header = '🔄 *再レビュー* ' + mention + '\n' + data.parentText;
messages.push({ text: header, ts: parentTs, channel: data.slackChannel });
messages.push({ text: data.linkMsg, ts: parentTs, channel: data.slackChannel });
for (const msg of data.issueMessages) {
  messages.push({ text: msg, ts: parentTs, channel: data.slackChannel });
}
if (data.goodMsg) messages.push({ text: data.goodMsg, ts: parentTs, channel: data.slackChannel });
if (data.manualMsg) messages.push({ text: data.manualMsg, ts: parentTs, channel: data.slackChannel });
if (data.switchCmd) messages.push({ text: data.switchCmd, ts: parentTs, channel: data.slackChannel });

return messages.map(m => ({ json: m }));

// SlackParentのtsを保存し、スレッド返信メッセージを生成
const staticData = $getWorkflowStaticData('global');
const threads = staticData.threads || {};
const data = $('ParseResult').item.json;
const parentTs = $input.first().json.message_timestamp;

// スレッドtsを保存
threads[data.pr._key] = parentTs;
staticData.threads = threads;

const messages = [];
messages.push({ text: data.linkMsg, ts: parentTs, channel: data.slackChannel });
for (const msg of data.issueMessages) {
  messages.push({ text: msg, ts: parentTs, channel: data.slackChannel });
}
if (data.goodMsg) messages.push({ text: data.goodMsg, ts: parentTs, channel: data.slackChannel });
if (data.manualMsg) messages.push({ text: data.manualMsg, ts: parentTs, channel: data.slackChannel });
if (data.switchCmd) messages.push({ text: data.switchCmd, ts: parentTs, channel: data.slackChannel });

if (messages.length === 0) {
  messages.push({ text: '✅ 問題なし', ts: parentTs, channel: data.slackChannel });
}

return messages.map(m => ({ json: m }));
